use strict;
use warnings;
use CGI qw(:standard);

print "Content-type: text/html\n\n";

my $query = new CGI;
my $comment = $query->param('comment');
$comment ||= ""; # default to empty string if 'comment' parameter is not set.

# Output the HTML including the comment value
print "<div>$comment</div>";